export function registerMiscHandlers(
  ctx: IpcContext,
): void {
  // Dialog: open folder
  ipcMain.handle("dialog:open-folder", async () => {
    const win = ctx.mainWindow();
    if (!win) return null;
    const result = await dialog.showOpenDialog(win, {
      properties: ["openDirectory"],
    });
    if (result.canceled || result.filePaths.length === 0) {
      return null;
    }
    return result.filePaths[0]!;
  });

  // Dialog: open image
  ipcMain.handle("dialog:open-image", async () => {
    const win = ctx.mainWindow();
    if (!win) return null;
    const result = await dialog.showOpenDialog(win, {
      properties: ["openFile"],
      filters: [
        {
          name: "Images",
          extensions: [
            "png",
            "jpg",
            "jpeg",
            "gif",
            "webp",
            "bmp",
            "tiff",
            "tif",
            "avif",
            "heic",
            "heif",
          ],
        },
      ],
    });
    if (result.canceled || result.filePaths.length === 0) {
      return null;
    }
    return result.filePaths[0]!;
  });

  // Dialog: confirm
  ipcMain.handle(
    "dialog:confirm",
    async (
      _event,
      opts: {
        message: string;
        detail?: string;
        buttons?: string[];
      },
    ) => {
      const win = ctx.mainWindow();
      if (!win) return 0;
      const result = await dialog.showMessageBox(win, {
        type: "warning",
        message: opts.message,
        detail: opts.detail,
        buttons: opts.buttons ?? ["OK", "Cancel"],
      });
      return result.response;
    },
  );

  // Context menu
  ipcMain.handle(
    "context-menu:show",
    async (
      _event,
